import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';
import { SchedulingResult, ProcessResult } from '../../models/scheduling.model';
import { Process } from '../../models/process.model';

interface CompareItem {
  name: string;
  result: SchedulingResult;
}

@Component({
  selector: 'app-metrics-panel',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './metrics-panel.component.html',
  styleUrls: ['./metrics-panel.component.scss']
})
export class MetricsPanelComponent {
  @Input() result: SchedulingResult | null = null;
  @Input() processes: Process[] = [];
  @Input() compareResults: CompareItem[] | null = null;
  @Input() compareMode: boolean = false;

  statsExpanded: boolean = false;

  readonly barColors = [
    '#4285F4',
    '#EA4335',
    '#FBBC04',
    '#34A853',
    '#9C27B0',
    '#00BCD4',
    '#FF5722'
  ];

  toggleStats(): void {
    this.statsExpanded = !this.statsExpanded;
  }

  getPreemptionEntries(result: SchedulingResult): { name: string; count: number }[] {
    const entries: { name: string; count: number }[] = [];
    if (!result.preemptionCounts) return entries;
    for (const p of this.processes) {
      const count = result.preemptionCounts.get(p.id) || 0;
      entries.push({ name: p.name, count });
    }
    return entries;
  }

  getProcessColor(processId: number): string {
    const process = this.processes.find(p => p.id === processId);
    return process?.color || '#6c757d';
  }

  getAverageRow(processResults: ProcessResult[] | undefined) {
    if (!processResults || processResults.length === 0) {
      return { turnaroundTime: 0, waitingTime: 0, responseTime: 0, startTime: 0, completionTime: 0 };
    }
    const count = processResults.length;
    return {
      turnaroundTime: processResults.reduce((sum, p) => sum + p.turnaroundTime, 0) / count,
      waitingTime: processResults.reduce((sum, p) => sum + p.waitingTime, 0) / count,
      responseTime: processResults.reduce((sum, p) => sum + p.responseTime, 0) / count,
      startTime: processResults.reduce((sum, p) => sum + p.startTime, 0) / count,
      completionTime: processResults.reduce((sum, p) => sum + p.completionTime, 0) / count
    };
  }

  getBarHeight(value: number, max: number): number {
    if (max === 0) return 0;
    return (value / max) * 100;
  }

  getMaxAvgWaitingTime(): number {
    if (!this.compareResults || this.compareResults.length === 0) return 0;
    return Math.max(...this.compareResults.map(c => c.result.avgWaitingTime));
  }

  getMaxAvgTurnaroundTime(): number {
    if (!this.compareResults || this.compareResults.length === 0) return 0;
    return Math.max(...this.compareResults.map(c => c.result.avgTurnaroundTime));
  }

  getBarColor(index: number): string {
    return this.barColors[index % this.barColors.length];
  }

  isBestTurnaround(index: number): boolean {
    if (!this.compareResults || this.compareResults.length === 0) return false;
    const values = this.compareResults.map(c => c.result.avgTurnaroundTime);
    const min = Math.min(...values);
    return this.compareResults[index].result.avgTurnaroundTime === min;
  }

  isBestWaiting(index: number): boolean {
    if (!this.compareResults || this.compareResults.length === 0) return false;
    const values = this.compareResults.map(c => c.result.avgWaitingTime);
    const min = Math.min(...values);
    return this.compareResults[index].result.avgWaitingTime === min;
  }

  isBestResponse(index: number): boolean {
    if (!this.compareResults || this.compareResults.length === 0) return false;
    const values = this.compareResults.map(c => c.result.avgResponseTime);
    const min = Math.min(...values);
    return this.compareResults[index].result.avgResponseTime === min;
  }

  isBestCpu(index: number): boolean {
    if (!this.compareResults || this.compareResults.length === 0) return false;
    const values = this.compareResults.map(c => c.result.cpuUtilization);
    const max = Math.max(...values);
    return this.compareResults[index].result.cpuUtilization === max;
  }

  isBestThroughput(index: number): boolean {
    if (!this.compareResults || this.compareResults.length === 0) return false;
    const values = this.compareResults.map(c => c.result.throughput);
    const max = Math.max(...values);
    return this.compareResults[index].result.throughput === max;
  }

  formatNumber(value: number): string {
    return value.toFixed(2);
  }

  formatPercent(value: number): string {
    return (value * 100).toFixed(1) + '%';
  }
}
<div class="metrics-panel">
  <ng-container *ngIf="!compareMode; else compareModeTemplate">
    <ng-container *ngIf="result">
      <div class="section-title">进程指标</div>
      <div class="table-container">
        <table class="metrics-table">
          <thead>
            <tr>
              <th>进程ID</th>
              <th>周转时间</th>
              <th>等待时间</th>
              <th>响应时间</th>
              <th>开始时间</th>
              <th>完成时间</th>
            </tr>
          </thead>
          <tbody>
            <tr *ngFor="let pr of result.processResults">
              <td>
                <span class="process-id-badge" [style.backgroundColor]="getProcessColor(pr.processId)">
                  P{{ pr.processId }}
                </span>
              </td>
              <td>{{ formatNumber(pr.turnaroundTime) }}</td>
              <td>{{ formatNumber(pr.waitingTime) }}</td>
              <td>{{ formatNumber(pr.responseTime) }}</td>
              <td>{{ formatNumber(pr.startTime) }}</td>
              <td>{{ formatNumber(pr.completionTime) }}</td>
            </tr>
            <tr class="average-row">
              <td><strong>平均值</strong></td>
              <td><strong>{{ formatNumber(getAverageRow(result.processResults).turnaroundTime) }}</strong></td>
              <td><strong>{{ formatNumber(getAverageRow(result.processResults).waitingTime) }}</strong></td>
              <td><strong>{{ formatNumber(getAverageRow(result.processResults).responseTime) }}</strong></td>
              <td><strong>{{ formatNumber(getAverageRow(result.processResults).startTime) }}</strong></td>
              <td><strong>{{ formatNumber(getAverageRow(result.processResults).completionTime) }}</strong></td>
            </tr>
          </tbody>
        </table>
      </div>

      <div class="section-title">全局指标</div>
      <div class="cards-grid">
        <div class="metric-card cpu-card">
          <div class="card-label">CPU利用率</div>
          <div class="card-value">{{ formatPercent(result.cpuUtilization) }}</div>
          <div class="progress-bar">
            <div class="progress-fill" [style.width.%]="(result.cpuUtilization * 100)"></div>
          </div>
        </div>

        <div class="metric-card">
          <div class="card-label">吞吐量</div>
          <div class="card-value">{{ formatNumber(result.throughput) }} 个/单位时间</div>
        </div>

        <div class="metric-card">
          <div class="card-label">平均周转时间</div>
          <div class="card-value">{{ formatNumber(result.avgTurnaroundTime) }}</div>
        </div>

        <div class="metric-card">
          <div class="card-label">平均等待时间</div>
          <div class="card-value">{{ formatNumber(result.avgWaitingTime) }}</div>
        </div>

        <div class="metric-card">
          <div class="card-label">平均响应时间</div>
          <div class="card-value">{{ formatNumber(result.avgResponseTime) }}</div>
        </div>

        <div class="metric-card">
          <div class="card-label">总运行时间</div>
          <div class="card-value">{{ formatNumber(result.totalTime) }} 时间单位</div>
        </div>
      </div>

      <div class="stats-collapsible">
        <div class="stats-header" (click)="toggleStats()">
          <span class="stats-title">📋 调度统计</span>
          <span class="stats-toggle">{{ statsExpanded ? '▲' : '▼' }}</span>
        </div>
        <div class="stats-body" *ngIf="statsExpanded">
          <div class="stats-summary-grid">
            <div class="stat-item">
              <div class="stat-label">上下文切换次数</div>
              <div class="stat-value">{{ result.contextSwitchCount }}</div>
            </div>
            <div class="stat-item">
              <div class="stat-label">CPU空闲时间片</div>
              <div class="stat-value">{{ result.cpuIdleTicks }}</div>
            </div>
          </div>
          <div class="section-title" style="margin-top: 16px;">进程抢占次数</div>
          <div class="table-container">
            <table class="metrics-table">
              <thead>
                <tr>
                  <th>进程</th>
                  <th>被抢占次数</th>
                </tr>
              </thead>
              <tbody>
                <tr *ngFor="let entry of getPreemptionEntries(result)">
                  <td>{{ entry.name }}</td>
                  <td>{{ entry.count }}</td>
                </tr>
                <tr *ngIf="getPreemptionEntries(result).length === 0">
                  <td colspan="2" style="text-align: center; color: #999;">无抢占发生</td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </ng-container>
  </ng-container>

  <ng-template #compareModeTemplate>
    <ng-container *ngIf="compareResults && compareResults.length > 0">
      <div class="section-title">算法对比图表</div>
      <div class="charts-grid">
        <div class="chart-container">
          <div class="chart-title">平均等待时间</div>
          <div class="bar-chart">
            <div class="bars-wrapper">
              <div class="bar-item" *ngFor="let item of compareResults; let i = index">
                <div class="bar-value">{{ formatNumber(item.result.avgWaitingTime) }}</div>
                <div
                  class="bar"
                  [style.backgroundColor]="getBarColor(i)"
                  [style.height.%]="getBarHeight(item.result.avgWaitingTime, getMaxAvgWaitingTime())"
                ></div>
                <div class="bar-label">{{ item.name }}</div>
              </div>
            </div>
          </div>
        </div>

        <div class="chart-container">
          <div class="chart-title">平均周转时间</div>
          <div class="bar-chart">
            <div class="bars-wrapper">
              <div class="bar-item" *ngFor="let item of compareResults; let i = index">
                <div class="bar-value">{{ formatNumber(item.result.avgTurnaroundTime) }}</div>
                <div
                  class="bar"
                  [style.backgroundColor]="getBarColor(i)"
                  [style.height.%]="getBarHeight(item.result.avgTurnaroundTime, getMaxAvgTurnaroundTime())"
                ></div>
                <div class="bar-label">{{ item.name }}</div>
              </div>
            </div>
          </div>
        </div>

        <div class="chart-container">
          <div class="chart-title">CPU利用率</div>
          <div class="bar-chart">
            <div class="bars-wrapper">
              <div class="bar-item" *ngFor="let item of compareResults; let i = index">
                <div class="bar-value">{{ formatPercent(item.result.cpuUtilization) }}</div>
                <div
                  class="bar"
                  [style.backgroundColor]="getBarColor(i)"
                  [style.height.%]="(item.result.cpuUtilization * 100)"
                ></div>
                <div class="bar-label">{{ item.name }}</div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div class="section-title">对比数据详情</div>
      <div class="table-container">
        <table class="metrics-table compare-table">
          <thead>
            <tr>
              <th>算法</th>
              <th>平均周转时间</th>
              <th>平均等待时间</th>
              <th>平均响应时间</th>
              <th>CPU利用率</th>
              <th>吞吐量</th>
              <th>上下文切换</th>
              <th>CPU空闲时间片</th>
            </tr>
          </thead>
          <tbody>
            <tr *ngFor="let item of compareResults; let i = index">
              <td>
                <span class="algo-badge" [style.backgroundColor]="getBarColor(i)">
                  {{ item.name }}
                </span>
              </td>
              <td [class.best-value]="isBestTurnaround(i)">{{ formatNumber(item.result.avgTurnaroundTime) }}</td>
              <td [class.best-value]="isBestWaiting(i)">{{ formatNumber(item.result.avgWaitingTime) }}</td>
              <td [class.best-value]="isBestResponse(i)">{{ formatNumber(item.result.avgResponseTime) }}</td>
              <td [class.best-value]="isBestCpu(i)">{{ formatPercent(item.result.cpuUtilization) }}</td>
              <td [class.best-value]="isBestThroughput(i)">{{ formatNumber(item.result.throughput) }}</td>
              <td>{{ item.result.contextSwitchCount }}</td>
              <td>{{ item.result.cpuIdleTicks }}</td>
            </tr>
          </tbody>
        </table>
      </div>
    </ng-container>
  </ng-template>
</div>
